CREATE OR REPLACE FUNCTION get_workflow_steps_label(p_workflow_step_id TEXT)
RETURNS TEXT AS $$
BEGIN
  RETURN (SELECT label FROM workflow_steps WHERE workflow_step_id = p_workflow_step_id);
END;
$$ LANGUAGE plpgsql STABLE SECURITY DEFINER;

